package com.backend.ccasa.service.impl.support;

import com.backend.ccasa.persistence.entities.entry.EntryConductivityEntity;
import com.backend.ccasa.service.IReferenceParameterService;
import com.backend.ccasa.service.models.enums.ConductivityTypeEnum;
import java.math.BigDecimal;
import org.springframework.stereotype.Component;

/**
 * RF-05: lectura directa en mS/cm frente a min/max RF05.
 * Conductividad teórica KCl: con {@code weightGrams}, se contrasta {@code calculatedValue} (µS/cm) con
 * {@link ReferenceParameterCodes#KCL_HIGH_THEORETICAL_U_CM} (alta) o {@link ReferenceParameterCodes#KCL_LOW_THEORETICAL_U_CM} (baja).
 */
@Component
public class ConductivityEntryComputation {

	public void apply(EntryConductivityEntity e, IReferenceParameterService refs) {
		if (e.getType() == ConductivityTypeEnum.High && e.getWeightGrams() != null) {
			BigDecimal v = e.getCalculatedValue();
			if (v == null) {
				e.setInRange(null);
				return;
			}
			BigDecimal min = refs.getMinValue(
				ReferenceParameterCodes.KCL_HIGH_THEORETICAL_U_CM,
				ReferenceParameterDefaults.KCL_HIGH_THEORY_MIN_U_CM
			);
			BigDecimal max = refs.getMaxValue(
				ReferenceParameterCodes.KCL_HIGH_THEORETICAL_U_CM,
				ReferenceParameterDefaults.KCL_HIGH_THEORY_MAX_U_CM
			);
			e.setInRange(v.compareTo(min) >= 0 && v.compareTo(max) <= 0);
			return;
		}
		if (e.getType() == ConductivityTypeEnum.Low && e.getWeightGrams() != null) {
			BigDecimal v = e.getCalculatedValue();
			if (v == null) {
				e.setInRange(null);
				return;
			}
			BigDecimal min = refs.getMinValue(
				ReferenceParameterCodes.KCL_LOW_THEORETICAL_U_CM,
				ReferenceParameterDefaults.KCL_LOW_THEORY_MIN_U_CM
			);
			BigDecimal max = refs.getMaxValue(
				ReferenceParameterCodes.KCL_LOW_THEORETICAL_U_CM,
				ReferenceParameterDefaults.KCL_LOW_THEORY_MAX_U_CM
			);
			e.setInRange(v.compareTo(min) >= 0 && v.compareTo(max) <= 0);
			return;
		}
		if (e.getMeasuredValue() != null && e.getCalculatedValue() == null) {
			e.setCalculatedValue(e.getMeasuredValue());
		}
		BigDecimal v = e.getCalculatedValue() != null ? e.getCalculatedValue() : e.getMeasuredValue();
		if (v == null || e.getType() == null) {
			e.setInRange(null);
			return;
		}
		BigDecimal min;
		BigDecimal max;
		if (e.getType() == ConductivityTypeEnum.High) {
			min = refs.getMinValue(ReferenceParameterCodes.RF05_CONDUCTIVITY_HIGH, ReferenceParameterDefaults.RF05_HIGH_MIN);
			max = refs.getMaxValue(ReferenceParameterCodes.RF05_CONDUCTIVITY_HIGH, ReferenceParameterDefaults.RF05_HIGH_MAX);
		} else {
			min = refs.getMinValue(ReferenceParameterCodes.RF05_CONDUCTIVITY_LOW, ReferenceParameterDefaults.RF05_LOW_MIN);
			max = refs.getMaxValue(ReferenceParameterCodes.RF05_CONDUCTIVITY_LOW, ReferenceParameterDefaults.RF05_LOW_MAX);
		}
		e.setInRange(v.compareTo(min) >= 0 && v.compareTo(max) <= 0);
	}
}

package com.backend.ccasa.service.impl.support;

import com.backend.ccasa.persistence.entities.entry.EntryConductivityEntity;
import com.backend.ccasa.service.IReferenceParameterService;
import com.backend.ccasa.service.models.enums.ConductivityTypeEnum;
import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import org.springframework.stereotype.Component;

/**
 * Conductividad baja (ej. 20-108-01): misma cadena Excel que alta en hojas YYYYMMDD (excel_formulas.json).
 * Usa parámetros {@code KCL_LOW_*}.
 */
@Component
public class ConductivityLowKclComputation {

	private static final MathContext MC = new MathContext(14, RoundingMode.HALF_UP);

	public void apply(EntryConductivityEntity e, IReferenceParameterService refs) {
		if (e.getType() != ConductivityTypeEnum.Low || e.getWeightGrams() == null) {
			return;
		}
		BigDecimal weight = e.getWeightGrams();
		if (weight.compareTo(BigDecimal.ZERO) <= 0) {
			return;
		}
		BigDecimal c25 = scalar(refs, ReferenceParameterCodes.KCL_LOW_C25, ReferenceParameterDefaults.KCL_LOW_C25);
		BigDecimal b24 = scalar(refs, ReferenceParameterCodes.KCL_LOW_B24, ReferenceParameterDefaults.KCL_LOW_B24);
		BigDecimal c24 = scalar(refs, ReferenceParameterCodes.KCL_LOW_C24, ReferenceParameterDefaults.KCL_LOW_C24);
		BigDecimal f24 = scalar(refs, ReferenceParameterCodes.KCL_LOW_F24, ReferenceParameterDefaults.KCL_LOW_F24);
		BigDecimal d28 = scalar(refs, ReferenceParameterCodes.KCL_LOW_D28, ReferenceParameterDefaults.KCL_LOW_D28);
		BigDecimal f28 = scalar(refs, ReferenceParameterCodes.KCL_LOW_F28, ReferenceParameterDefaults.KCL_LOW_F28);

		if (c24.compareTo(BigDecimal.ZERO) == 0 || d28.compareTo(BigDecimal.ZERO) == 0) {
			return;
		}
		BigDecimal c26 = c25.multiply(b24, MC).divide(c24, MC);
		BigDecimal f26 = weight.multiply(f24, MC).divide(c26, MC);
		e.setCalculatedMol(f26);
		BigDecimal f30 = f26.multiply(f28, MC).divide(d28, MC);
		e.setCalculatedValue(f30);
	}

	private static BigDecimal scalar(IReferenceParameterService refs, String code, BigDecimal defaultValue) {
		BigDecimal min = refs.getMinValue(code, defaultValue);
		BigDecimal max = refs.getMaxValue(code, defaultValue);
		if (min != null && max != null && min.compareTo(max) == 0) {
			return min;
		}
		return min != null ? min : max != null ? max : defaultValue;
	}
}

package com.backend.ccasa.service.impl.support;

import com.backend.ccasa.persistence.entities.entry.EntryConductivityEntity;
import com.backend.ccasa.service.IReferenceParameterService;
import com.backend.ccasa.service.models.enums.ConductivityTypeEnum;
import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import org.springframework.stereotype.Component;

/**
 * Bitácora 20-108 conductividad alta: cadena Excel (hoja fecha) para estándar KCl.
 * C26=C25*B24/C24; F26=(peso*F24)/C26 con peso en g (E25=B10 en Excel → {@code weightGrams});
 * D29=F26; F30=(D29*F28)/D28. Resultado teórico en µS/cm (misma magnitud que F28).
 */
@Component
public class ConductivityHighKclComputation {

	private static final MathContext MC = new MathContext(14, RoundingMode.HALF_UP);

	public void apply(EntryConductivityEntity e, IReferenceParameterService refs) {
		if (e.getType() != ConductivityTypeEnum.High || e.getWeightGrams() == null) {
			return;
		}
		BigDecimal weight = e.getWeightGrams();
		if (weight.compareTo(BigDecimal.ZERO) <= 0) {
			return;
		}
		BigDecimal c25 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_C25, ReferenceParameterDefaults.KCL_HIGH_C25);
		BigDecimal b24 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_B24, ReferenceParameterDefaults.KCL_HIGH_B24);
		BigDecimal c24 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_C24, ReferenceParameterDefaults.KCL_HIGH_C24);
		BigDecimal f24 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_F24, ReferenceParameterDefaults.KCL_HIGH_F24);
		BigDecimal d28 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_D28, ReferenceParameterDefaults.KCL_HIGH_D28);
		BigDecimal f28 = scalar(refs, ReferenceParameterCodes.KCL_HIGH_F28, ReferenceParameterDefaults.KCL_HIGH_F28);

		if (c24.compareTo(BigDecimal.ZERO) == 0 || d28.compareTo(BigDecimal.ZERO) == 0) {
			return;
		}
		// C26 = C25*B24/C24
		BigDecimal c26 = c25.multiply(b24, MC).divide(c24, MC);
		// F26 = (peso * F24) / C26  (Excel: (E25*F24)/E24, E25=peso, E24=C26)
		BigDecimal f26 = weight.multiply(f24, MC).divide(c26, MC);
		e.setCalculatedMol(f26);
		// F30 = (D29*F28)/D28, D29=F26
		BigDecimal f30 = f26.multiply(f28, MC).divide(d28, MC);
		e.setCalculatedValue(f30);
	}

	private static BigDecimal scalar(IReferenceParameterService refs, String code, BigDecimal defaultValue) {
		BigDecimal min = refs.getMinValue(code, defaultValue);
		BigDecimal max = refs.getMaxValue(code, defaultValue);
		if (min != null && max != null && min.compareTo(max) == 0) {
			return min;
		}
		return min != null ? min : max != null ? max : defaultValue;
	}
}

package com.backend.ccasa.persistence.entities.entry;

import com.backend.ccasa.persistence.entities.EntryEntity;
import com.backend.ccasa.persistence.entities.audit.Auditable;
import com.backend.ccasa.service.models.enums.ConductivityTypeEnum;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.FetchType;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.Table;
import java.math.BigDecimal;
import java.time.Instant;

/**
 * Entrada de conductividad (RF-05: alta 0.7440â€“0.7490, baja 0.0744â€“0.0790).
 */
@Entity
@Table(name = "entry_conductivity")
public class EntryConductivityEntity extends Auditable {

	@Id
	@GeneratedValue(strategy = GenerationType.IDENTITY)
	@Column(name = "conductivity_entry_id")
	private Long id;

	@ManyToOne(fetch = FetchType.LAZY)
	@JoinColumn(name = "entry_id", nullable = false)
	private EntryEntity entry;

	@Enumerated(EnumType.STRING)
	@Column(name = "type", length = 20)
	private ConductivityTypeEnum type;

	@Column(name = "measured_value", precision = 8, scale = 4)
	private BigDecimal measuredValue;

	/** Peso (g) para cadena KCl 20-108; si está informado, la conductividad teórica va en calculated_value (µS/cm). */
	@Column(name = "weight_grams", precision = 12, scale = 6)
	private BigDecimal weightGrams;

	@Column(name = "calculated_mol", precision = 10, scale = 6)
	private BigDecimal calculatedMol;

	@Column(name = "calculated_value", precision = 10, scale = 6)
	private BigDecimal calculatedValue;

	@Column(name = "in_range")
	private Boolean inRange;

	@Column(name = "auto_date")
	private Instant autoDate;

	public Long getId() { return id; }
	public void setId(Long id) { this.id = id; }
	public EntryEntity getEntry() { return entry; }
	public void setEntry(EntryEntity entry) { this.entry = entry; }
	public ConductivityTypeEnum getType() { return type; }
	public void setType(ConductivityTypeEnum type) { this.type = type; }
	public BigDecimal getMeasuredValue() { return measuredValue; }
	public void setMeasuredValue(BigDecimal measuredValue) { this.measuredValue = measuredValue; }
	public BigDecimal getWeightGrams() { return weightGrams; }
	public void setWeightGrams(BigDecimal weightGrams) { this.weightGrams = weightGrams; }
	public BigDecimal getCalculatedMol() { return calculatedMol; }
	public void setCalculatedMol(BigDecimal calculatedMol) { this.calculatedMol = calculatedMol; }
	public BigDecimal getCalculatedValue() { return calculatedValue; }
	public void setCalculatedValue(BigDecimal calculatedValue) { this.calculatedValue = calculatedValue; }
	public Boolean getInRange() { return inRange; }
	public void setInRange(Boolean inRange) { this.inRange = inRange; }
	public Instant getAutoDate() { return autoDate; }
	public void setAutoDate(Instant autoDate) { this.autoDate = autoDate; }
}

package com.backend.ccasa.service.impl;

import com.backend.ccasa.persistence.entities.entry.EntryConductivityEntity;
import com.backend.ccasa.persistence.repositories.EntryConductivityRepository;
import com.backend.ccasa.service.IEntryConductivityCrudService;
import com.backend.ccasa.service.IReferenceParameterService;
import com.backend.ccasa.service.impl.support.ConductivityEntryComputation;
import com.backend.ccasa.service.impl.support.ConductivityHighKclComputation;
import com.backend.ccasa.service.impl.support.ConductivityLowKclComputation;
import jakarta.persistence.EntityManager;
import org.springframework.stereotype.Service;

@Service
public class EntryConductivityCrudService extends AbstractEntityCrudService<EntryConductivityEntity> implements IEntryConductivityCrudService {

	private final ConductivityHighKclComputation conductivityHighKclComputation;
	private final ConductivityLowKclComputation conductivityLowKclComputation;
	private final ConductivityEntryComputation conductivityEntryComputation;
	private final IReferenceParameterService referenceParameterService;

	public EntryConductivityCrudService(
		EntryConductivityRepository repository,
		EntityManager entityManager,
		ConductivityHighKclComputation conductivityHighKclComputation,
		ConductivityLowKclComputation conductivityLowKclComputation,
		ConductivityEntryComputation conductivityEntryComputation,
		IReferenceParameterService referenceParameterService
	) {
		super(repository, entityManager, EntryConductivityEntity.class, "E_NT_RY_CO_ND_UC_TI_VI_TY");
		this.conductivityHighKclComputation = conductivityHighKclComputation;
		this.conductivityLowKclComputation = conductivityLowKclComputation;
		this.conductivityEntryComputation = conductivityEntryComputation;
		this.referenceParameterService = referenceParameterService;
	}

	@Override
	protected void afterApply(EntryConductivityEntity entity) {
		conductivityHighKclComputation.apply(entity, referenceParameterService);
		conductivityLowKclComputation.apply(entity, referenceParameterService);
		conductivityEntryComputation.apply(entity, referenceParameterService);
	}

	@Override
	protected EntryConductivityEntity newEntity() {
		return new EntryConductivityEntity();
	}
}

